export type NotamType = 'TFR' | 'MIL' | 'CONFLICT' | 'LAUNCH' | 'VIP';
export type NotamSeverity = 'critical' | 'high' | 'medium' | 'low';
export type Region = 'Global' | 'Europe' | 'Middle East' | 'Asia-Pacific' | 'Americas' | 'Africa';

export interface NotamEntry {
  id: string;
  notamId: string;
  type: NotamType;
  severity: NotamSeverity;
  location: string;
  fir: string;
  country: string;
  region: Region;
  lat: number;
  lng: number;
  radius: number; // nautical miles (legacy)
  countryId?: string; // ISO 3166-1 numeric code for country-level highlighting
  areaRadiusKm?: number; // km radius for area-level circle polygons
  lowerAlt: string;
  upperAlt: string;
  effectiveFrom: string; // ISO date
  effectiveTo: string;   // ISO date
  issuedAt: string;
  description: string;
  rawText: string;
  keywords: string[];
  isConflictZone: boolean;
  isNew: boolean; // issued within 6 hours
}

export const TYPE_COLORS: Record<NotamType, string> = {
  CONFLICT: '#ef4444',
  MIL: '#f97316',
  TFR: '#eab308',
  LAUNCH: '#3b82f6',
  VIP: '#a855f7',
};

export const TYPE_LABELS: Record<NotamType, string> = {
  CONFLICT: 'PROHIBITED / CONFLICT',
  MIL: 'MILITARY EXERCISE',
  TFR: 'TEMP FLIGHT RESTRICTION',
  LAUNCH: 'LAUNCH WINDOW',
  VIP: 'VIP MOVEMENT',
};

export const SEVERITY_COLORS: Record<NotamSeverity, string> = {
  critical: '#ef4444',
  high: '#f97316',
  medium: '#eab308',
  low: '#22c55e',
};

export const CONFLICT_ZONES = ['Ukraine', 'Gaza', 'Yemen', 'Sudan', 'Myanmar', 'Syria', 'Iran', 'Lebanon', 'Somalia', 'Iraq', 'Libya', 'Afghanistan'];

export const REGIONS: Region[] = ['Global', 'Europe', 'Middle East', 'Asia-Pacific', 'Americas', 'Africa'];

