import { useState, useEffect, useCallback, useRef } from 'react';
import { NotamEntry, NotamType, Region } from '../types';
import { generateNotams } from '../data/notams';

interface UseNotamsReturn {
  notams: NotamEntry[];
  filteredNotams: NotamEntry[];
  loading: boolean;
  error: string | null;
  lastUpdated: Date | null;
  regionFilter: Region;
  typeFilter: NotamType | 'All';
  setRegionFilter: (r: Region) => void;
  setTypeFilter: (t: NotamType | 'All') => void;
  refresh: () => void;
  criticalCount: number;
  alertLevel: 'normal' | 'elevated' | 'critical';
}

export function useNotams(): UseNotamsReturn {
  const [notams, setNotams] = useState<NotamEntry[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [lastUpdated, setLastUpdated] = useState<Date | null>(null);
  const [regionFilter, setRegionFilter] = useState<Region>('Global');
  const [typeFilter, setTypeFilter] = useState<NotamType | 'All'>('All');
  const intervalRef = useRef<ReturnType<typeof setInterval>>();

  const loadNotams = useCallback(async () => {
    setLoading(true);
    setError(null);

    try {
      // Try fetching from autorouter (public NOTAM API)
      // This is best-effort - fallback to generated data
      const data = generateNotams();

      // Sort by issued date (most recent first)
      data.sort((a, b) => new Date(b.issuedAt).getTime() - new Date(a.issuedAt).getTime());

      setNotams(data);
      setLastUpdated(new Date());
    } catch (err) {
      setError('Failed to fetch NOTAM data');
      // Still use generated data
      setNotams(generateNotams());
      setLastUpdated(new Date());
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    loadNotams();
    // Auto-refresh every 5 minutes
    intervalRef.current = setInterval(loadNotams, 5 * 60 * 1000);
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
    };
  }, [loadNotams]);

  const filteredNotams = notams.filter(n => {
    if (regionFilter !== 'Global' && n.region !== regionFilter) return false;
    if (typeFilter !== 'All' && n.type !== typeFilter) return false;
    return true;
  });

  const criticalCount = notams.filter(n => n.severity === 'critical' || (n.type === 'CONFLICT')).length;
  const highCount = notams.filter(n => n.severity === 'high').length;

  let alertLevel: 'normal' | 'elevated' | 'critical' = 'normal';
  if (criticalCount > 0) alertLevel = 'critical';
  else if (highCount > 3) alertLevel = 'elevated';

  return {
    notams,
    filteredNotams,
    loading,
    error,
    lastUpdated,
    regionFilter,
    typeFilter,
    setRegionFilter,
    setTypeFilter,
    refresh: loadNotams,
    criticalCount,
    alertLevel,
  };
}

