import { useEffect, useRef } from 'react';
import maplibregl from 'maplibre-gl';
import 'maplibre-gl/dist/maplibre-gl.css';
import * as topojson from 'topojson-client';
import { NotamEntry } from '../types';

/* ── Color config ─────────────────────────────────────── */
const TYPE_FILL: Record<string, string> = {
  CONFLICT: 'rgba(220, 38, 38, 0.42)',
  MIL:      'rgba(234, 88, 12, 0.32)',
  TFR:      'rgba(234, 179, 8, 0.28)',
  LAUNCH:   'rgba(59, 130, 246, 0.28)',
  VIP:      'rgba(168, 85, 247, 0.28)',
};
const TYPE_BORDER: Record<string, string> = {
  CONFLICT: '#dc2626',
  MIL:      '#ea580c',
  TFR:      '#eab308',
  LAUNCH:   '#3b82f6',
  VIP:      '#a855f7',
};
const TYPE_LABEL: Record<string, string> = {
  CONFLICT: '#fca5a5',
  MIL:      '#fdba74',
  TFR:      '#fde047',
  LAUNCH:   '#93c5fd',
  VIP:      '#c4b5fd',
};

/* ── Circle polygon generator ─────────────────────────── */
function circlePolygon(center: [number, number], rKm: number, n = 64): number[][] {
  const [lng, lat] = center;
  const pts: number[][] = [];
  for (let i = 0; i <= n; i++) {
    const a = (i / n) * 2 * Math.PI;
    const dLat = (rKm / 111.32) * Math.cos(a);
    const dLng = (rKm / (111.32 * Math.cos(lat * Math.PI / 180))) * Math.sin(a);
    pts.push([lng + dLng, lat + dLat]);
  }
  return pts;
}

/* ── Popup CSS injection ──────────────────────────────── */
const POPUP_CSS = `
.maplibregl-popup-content{background:#18181b!important;color:#e4e4e7!important;border-radius:0!important;padding:0!important;box-shadow:0 4px 16px rgba(0,0,0,.6)!important}
.maplibregl-popup-close-button{color:#71717a!important;font-size:18px!important;right:4px!important;top:2px!important}
.maplibregl-popup-close-button:hover{color:#fafafa!important;background:transparent!important}
.maplibregl-popup-tip{border-top-color:#18181b!important;border-bottom-color:#18181b!important}
`;

interface Props {
  notams: NotamEntry[];
}

export function NotamMap({ notams }: Props) {
  const containerRef = useRef<HTMLDivElement>(null);
  const mapRef = useRef<maplibregl.Map | null>(null);
  const markersRef = useRef<maplibregl.Marker[]>([]);
  const countriesRef = useRef<any>(null);
  const readyRef = useRef(false);
  const notamsRef = useRef(notams);
  notamsRef.current = notams;

  /* ── Inject popup CSS once ── */
  useEffect(() => {
    if (!document.getElementById('notam-popup-css')) {
      const s = document.createElement('style');
      s.id = 'notam-popup-css';
      s.textContent = POPUP_CSS;
      document.head.appendChild(s);
    }
  }, []);

  /* ── Initialize map ── */
  useEffect(() => {
    if (!containerRef.current) return;

    const map = new maplibregl.Map({
      container: containerRef.current,
      style: {
        version: 8,
        sources: {
          carto: {
            type: 'raster',
            tiles: [
              'https://a.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png',
              'https://b.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png',
              'https://c.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}.png',
            ],
            tileSize: 256,
            attribution: '&copy; CARTO &copy; OpenStreetMap',
          },
        },
        layers: [{ id: 'carto-tiles', type: 'raster', source: 'carto' }],
      },
      center: [40, 22],
      zoom: 2.2,
      attributionControl: false,
    });

    mapRef.current = map;

    map.on('load', async () => {
      /* Fetch world country boundaries */
      try {
        const res = await fetch(
          'https://cdn.jsdelivr.net/npm/world-atlas@2/countries-110m.json'
        );
        const topo = await res.json();
        countriesRef.current = topojson.feature(topo, topo.objects.countries) as any;
      } catch (e) {
        console.warn('Failed to fetch world boundaries', e);
      }

      /* Add empty sources */
      map.addSource('notam-countries', {
        type: 'geojson',
        data: { type: 'FeatureCollection', features: [] },
      });
      map.addSource('notam-areas', {
        type: 'geojson',
        data: { type: 'FeatureCollection', features: [] },
      });

      /* Country fill */
      map.addLayer({
        id: 'countries-fill',
        type: 'fill',
        source: 'notam-countries',
        paint: {
          'fill-color': [
            'match', ['get', 'notamType'],
            'CONFLICT', TYPE_FILL.CONFLICT,
            'MIL',      TYPE_FILL.MIL,
            'TFR',      TYPE_FILL.TFR,
            'LAUNCH',   TYPE_FILL.LAUNCH,
            'VIP',      TYPE_FILL.VIP,
            'rgba(107,114,128,0.25)',
          ],
        },
      });

      /* Country border */
      map.addLayer({
        id: 'countries-border',
        type: 'line',
        source: 'notam-countries',
        paint: {
          'line-color': [
            'match', ['get', 'notamType'],
            'CONFLICT', TYPE_BORDER.CONFLICT,
            'MIL',      TYPE_BORDER.MIL,
            'TFR',      TYPE_BORDER.TFR,
            'LAUNCH',   TYPE_BORDER.LAUNCH,
            'VIP',      TYPE_BORDER.VIP,
            '#6b7280',
          ],
          'line-width': 2,
        },
      });

      /* Area fill */
      map.addLayer({
        id: 'areas-fill',
        type: 'fill',
        source: 'notam-areas',
        paint: {
          'fill-color': [
            'match', ['get', 'notamType'],
            'CONFLICT', TYPE_FILL.CONFLICT,
            'MIL',      TYPE_FILL.MIL,
            'TFR',      TYPE_FILL.TFR,
            'LAUNCH',   TYPE_FILL.LAUNCH,
            'VIP',      TYPE_FILL.VIP,
            'rgba(107,114,128,0.25)',
          ],
        },
      });

      /* Area border (dashed) */
      map.addLayer({
        id: 'areas-border',
        type: 'line',
        source: 'notam-areas',
        paint: {
          'line-color': [
            'match', ['get', 'notamType'],
            'CONFLICT', TYPE_BORDER.CONFLICT,
            'MIL',      TYPE_BORDER.MIL,
            'TFR',      TYPE_BORDER.TFR,
            'LAUNCH',   TYPE_BORDER.LAUNCH,
            'VIP',      TYPE_BORDER.VIP,
            '#6b7280',
          ],
          'line-width': 1.5,
          'line-dasharray': [4, 2],
        },
      });

      /* Click & hover handlers */
      for (const layerId of ['countries-fill', 'areas-fill']) {
        map.on('click', layerId, (e: any) => {
          if (!e.features?.[0]) return;
          const p = e.features[0].properties;
          const border = TYPE_BORDER[p.notamType] || '#6b7280';
          new maplibregl.Popup({ closeButton: true, maxWidth: '340px' })
            .setLngLat(e.lngLat)
            .setHTML(`
              <div style="font-family:monospace;font-size:11px;padding:10px;border:1px solid ${border};max-height:260px;overflow-y:auto">
                <div style="font-weight:bold;color:${border};font-size:12px;margin-bottom:4px">${p.location || ''}</div>
                <span style="background:${border}22;color:${border};padding:1px 6px;font-size:9px;letter-spacing:1px;display:inline-block;margin-bottom:6px">${p.notamType}</span>
                ${p.count > 1 ? `<span style="color:#71717a;font-size:9px;margin-left:6px">${p.count} NOTAM(S)</span>` : ''}
                <div style="color:#a1a1aa;line-height:1.5;white-space:pre-wrap">${(p.description || '').substring(0, 400)}</div>
              </div>
            `)
            .addTo(map);
        });
        map.on('mouseenter', layerId, () => {
          map.getCanvas().style.cursor = 'pointer';
        });
        map.on('mouseleave', layerId, () => {
          map.getCanvas().style.cursor = '';
        });
      }

      readyRef.current = true;
      applyData(map, notamsRef.current);
    });

    return () => {
      markersRef.current.forEach(m => m.remove());
      markersRef.current = [];
      readyRef.current = false;
      map.remove();
    };
  }, []); // mount once

  /* ── Update when notams change ── */
  useEffect(() => {
    if (!mapRef.current || !readyRef.current) return;
    applyData(mapRef.current, notams);
  }, [notams]);

  /* ── Core data application ── */
  function applyData(map: maplibregl.Map, notams: NotamEntry[]) {
    /* Clear old markers */
    markersRef.current.forEach(m => m.remove());
    markersRef.current = [];

    /* Group by country */
    const byCountry = new Map<string, { type: string; notams: NotamEntry[] }>();
    const areaNotams: NotamEntry[] = [];

    notams.forEach(n => {
      if (n.countryId) {
        const cur = byCountry.get(n.countryId);
        if (cur) {
          cur.notams.push(n);
          // CONFLICT always wins as the visual type
          if (n.type === 'CONFLICT') cur.type = 'CONFLICT';
        } else {
          byCountry.set(n.countryId, { type: n.type, notams: [n] });
        }
      } else if (n.areaRadiusKm) {
        areaNotams.push(n);
      }
    });

    /* Build country features */
    const countryFeatures: any[] = [];
    const countriesGeo = countriesRef.current;

    if (countriesGeo) {
      const featureMap = new Map<string, any>();
      countriesGeo.features.forEach((f: any) => {
        featureMap.set(String(f.id), f);
      });

      byCountry.forEach((data, cid) => {
        const feat = featureMap.get(cid);
        if (feat) {
          countryFeatures.push({
            ...feat,
            properties: {
              notamType: data.type,
              location: data.notams[0].location,
              description: data.notams.map((n: NotamEntry) => n.description).join('\n\n'),
              count: data.notams.length,
            },
          });
        } else {
          // Fallback: country not found in TopoJSON → create circle
          const n = data.notams[0];
          areaNotams.push({ ...n, areaRadiusKm: n.areaRadiusKm || 250 });
        }
      });
    } else {
      // No world data at all → push everything as areas
      byCountry.forEach((data) => {
        const n = data.notams[0];
        areaNotams.push({ ...n, areaRadiusKm: n.areaRadiusKm || 250 });
      });
    }

    /* Build area features */
    const areaFeatures = areaNotams.map(n => ({
      type: 'Feature' as const,
      properties: {
        notamType: n.type,
        location: n.location,
        description: n.description,
        count: 1,
      },
      geometry: {
        type: 'Polygon' as const,
        coordinates: [circlePolygon([n.lng, n.lat], n.areaRadiusKm || 100)],
      },
    }));

    /* Update sources */
    try {
      const cs = map.getSource('notam-countries') as maplibregl.GeoJSONSource;
      if (cs) cs.setData({ type: 'FeatureCollection', features: countryFeatures });
    } catch (_) {}

    try {
      const as = map.getSource('notam-areas') as maplibregl.GeoJSONSource;
      if (as) as.setData({ type: 'FeatureCollection', features: areaFeatures });
    } catch (_) {}

    /* Add label + dot markers */
    // Country labels
    const addedLabels = new Set<string>();
    byCountry.forEach((data, cid) => {
      const n = data.notams[0];
      const label = extractLabel(n.location);
      if (!addedLabels.has(label)) {
        addedLabels.add(label);
        addMarker(map, n.lng, n.lat, label, data.type, data.notams.length, n.severity === 'critical');
      }
    });

    // Area labels (only for larger areas)
    areaNotams.forEach(n => {
      if ((n.areaRadiusKm || 0) >= 40) {
        const label = extractLabel(n.location);
        addMarker(map, n.lng, n.lat, label, n.type, 1, n.severity === 'critical');
      } else {
        // Small dot only for small areas
        addSmallDot(map, n.lng, n.lat, n.type);
      }
    });
  }

  function extractLabel(location: string): string {
    // Keep it short: first 2-3 meaningful words
    return location
      .replace(/\s*-\s*/g, ' ')
      .replace(/AIRSPACE|AREA|REGION|CENTRAL|EASTERN|WESTERN|SOUTHERN|NORTHERN/gi, '')
      .trim()
      .split(/\s+/)
      .slice(0, 2)
      .join(' ')
      .toUpperCase();
  }

  function addMarker(
    map: maplibregl.Map,
    lng: number, lat: number,
    label: string, type: string,
    count: number, critical: boolean
  ) {
    const color = TYPE_BORDER[type] || '#6b7280';
    const labelColor = TYPE_LABEL[type] || '#e5e7eb';

    const el = document.createElement('div');
    el.style.cssText = 'display:flex;flex-direction:column;align-items:center;pointer-events:none;';

    // Label
    const txt = document.createElement('div');
    txt.style.cssText = `
      font-family:monospace;font-size:10px;font-weight:bold;
      color:${labelColor};letter-spacing:1px;white-space:nowrap;
      text-shadow:0 0 5px rgba(0,0,0,1),0 0 10px rgba(0,0,0,0.8),0 1px 3px rgba(0,0,0,1);
      margin-bottom:3px;
    `;
    txt.textContent = label;
    el.appendChild(txt);

    // Center dot
    const dot = document.createElement('div');
    dot.style.cssText = `
      width:${critical ? 12 : 9}px;height:${critical ? 12 : 9}px;
      border-radius:50%;background:${color};
      border:2px solid rgba(0,0,0,0.6);
      box-shadow:0 0 ${critical ? 10 : 6}px ${color}88;
    `;
    if (critical) {
      dot.style.animation = 'notam-pulse 2s ease-in-out infinite';
    }
    el.appendChild(dot);

    // Count badge
    if (count > 1) {
      const badge = document.createElement('div');
      badge.style.cssText = `
        font-family:monospace;font-size:8px;color:#a1a1aa;
        margin-top:2px;
      `;
      badge.textContent = `×${count}`;
      el.appendChild(badge);
    }

    const marker = new maplibregl.Marker({ element: el, anchor: 'center' })
      .setLngLat([lng, lat])
      .addTo(map);
    markersRef.current.push(marker);
  }

  function addSmallDot(map: maplibregl.Map, lng: number, lat: number, type: string) {
    const color = TYPE_BORDER[type] || '#6b7280';
    const el = document.createElement('div');
    el.style.cssText = `
      width:6px;height:6px;border-radius:50%;background:${color};
      border:1.5px solid rgba(0,0,0,0.5);box-shadow:0 0 4px ${color}66;
      pointer-events:none;
    `;
    const marker = new maplibregl.Marker({ element: el, anchor: 'center' })
      .setLngLat([lng, lat])
      .addTo(map);
    markersRef.current.push(marker);
  }

  return (
    <>
      <div ref={containerRef} style={{ position: 'absolute', top: 0, left: 0, right: 0, bottom: 0 }} />
      {/* Legend overlay */}
      <div style={{
        position: 'absolute', bottom: 10, right: 10,
        background: 'rgba(9,9,11,0.85)', border: '1px solid #27272a',
        padding: '8px 10px', fontFamily: 'monospace', fontSize: '9px',
        zIndex: 10, pointerEvents: 'none',
      }}>
        {[
          { type: 'CONFLICT', label: 'CONFLICT / PROHIBITED' },
          { type: 'MIL', label: 'MILITARY EXERCISE' },
          { type: 'TFR', label: 'TFR / RESTRICTION' },
          { type: 'LAUNCH', label: 'LAUNCH WINDOW' },
          { type: 'VIP', label: 'VIP MOVEMENT' },
        ].map(({ type, label }) => (
          <div key={type} style={{ display: 'flex', alignItems: 'center', gap: 6, marginBottom: 3, color: TYPE_LABEL[type] }}>
            <div style={{
              width: 10, height: 10, background: TYPE_FILL[type],
              border: `1.5px solid ${TYPE_BORDER[type]}`,
            }} />
            {label}
          </div>
        ))}
      </div>
      {/* Pulse animation */}
      <style>{`
        @keyframes notam-pulse {
          0%, 100% { transform: scale(1); opacity: 1; }
          50% { transform: scale(1.6); opacity: 0.6; }
        }
      `}</style>
    </>
  );
}

